<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Bouncing Ball Playground</title>
<style>
  :root {
    --bg: #12141a;
    --panel: #1c1f28;
    --accent: #5ac8fa;
    --text: #e6e8ee;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 16px;
    background: var(--bg);
    color: var(--text);
    font-family: system-ui, -apple-system, "Segoe UI", sans-serif;
  }
  h1 {
    font-size: 1.1rem;
    font-weight: 600;
    letter-spacing: 0.04em;
    margin: 0;
    color: #aab0c0;
  }
  #sim {
    width: 520px;
    height: 420px;
    max-width: 95vw;
    background: var(--panel);
    border-radius: 12px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.5), inset 0 0 0 1px #2a2e3a;
    cursor: crosshair;
    display: block;
  }
  .controls { display: flex; gap: 10px; }
  button {
    background: #262b38;
    color: var(--text);
    border: 1px solid #353b4c;
    border-radius: 8px;
    padding: 8px 18px;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background 0.15s, transform 0.05s;
  }
  button:hover { background: #313749; border-color: var(--accent); }
  button:active { transform: scale(0.96); }
  .hint { font-size: 0.8rem; color: #6b7180; }
</style>
</head>
<body>
<h1>Bouncing Ball Playground</h1>
<canvas id="sim"></canvas>
<div class="controls">
  <button id="drop">Drop Ball</button>
  <button id="play">Pause</button>
  <button id="clear">Clear</button>
</div>
<div class="hint">Click the canvas to add a ball at the cursor.</div>

<script>
(function () {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');

  const W = 520, H = 420;
  canvas.width = W;
  canvas.height = H;

  const GRAVITY = 0.35;       // per step, per unit dt
  const RESTITUTION = 0.82;   // energy kept on bounce
  const FRICTION = 0.995;     // mild air drag

  const COLORS = ['#5ac8fa', '#ff7a90', '#ffd166', '#8be08b', '#c792ea', '#f78c6c'];

  const balls = [];
  let running = true;

  function makeBall(x, y, vx, vy, r) {
    return {
      x, y, vx, vy,
      r: r !== undefined ? r : 8 + Math.random() * 12,
      color: COLORS[Math.floor(Math.random() * COLORS.length)],
    };
  }

  function addBall(x, y, vx = 0, vy = 0, r) {
    const b = makeBall(x, y, vx, vy, r);
    // Keep the spawn point inside the canvas.
    b.x = Math.min(Math.max(b.x, b.r), W - b.r);
    b.y = Math.min(Math.max(b.y, b.r), H - b.r);
    balls.push(b);
    draw();
    return b;
  }

  function physicsStep(dt) {
    for (const b of balls) {
      b.vy += GRAVITY * dt;
      b.vx *= Math.pow(FRICTION, dt);
      b.x += b.vx * dt;
      b.y += b.vy * dt;

      // Floor
      if (b.y + b.r > H) {
        b.y = H - b.r;
        if (b.vy > 0) b.vy = -b.vy * RESTITUTION;
      }
      // Ceiling
      if (b.y - b.r < 0) {
        b.y = b.r;
        if (b.vy < 0) b.vy = -b.vy * RESTITUTION;
      }
      // Right wall
      if (b.x + b.r > W) {
        b.x = W - b.r;
        if (b.vx > 0) b.vx = -b.vx * RESTITUTION;
      }
      // Left wall
      if (b.x - b.r < 0) {
        b.x = b.r;
        if (b.vx < 0) b.vx = -b.vx * RESTITUTION;
      }
    }
  }

  function draw() {
    ctx.clearRect(0, 0, W, H);
    for (const b of balls) {
      const grad = ctx.createRadialGradient(
        b.x - b.r * 0.35, b.y - b.r * 0.35, b.r * 0.1,
        b.x, b.y, b.r
      );
      grad.addColorStop(0, '#ffffff');
      grad.addColorStop(0.25, b.color);
      grad.addColorStop(1, b.color);
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fillStyle = grad;
      ctx.fill();
    }
  }

  function step(dt = 1) {
    physicsStep(dt);
    draw();
  }

  function loop() {
    if (running) step(1);
    requestAnimationFrame(loop);
  }

  // --- UI wiring ---
  document.getElementById('drop').addEventListener('click', () => {
    addBall(
      W * 0.2 + Math.random() * W * 0.6,
      30 + Math.random() * 40,
      (Math.random() - 0.5) * 6,
      0
    );
  });

  const playBtn = document.getElementById('play');
  playBtn.addEventListener('click', () => {
    running = !running;
    playBtn.textContent = running ? 'Pause' : 'Play';
  });

  document.getElementById('clear').addEventListener('click', () => {
    balls.length = 0;
    draw();
  });

  canvas.addEventListener('click', (e) => {
    const rect = canvas.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (W / rect.width);
    const y = (e.clientY - rect.top) * (H / rect.height);
    addBall(x, y, (Math.random() - 0.5) * 4, -2 - Math.random() * 3);
  });

  // --- Programmatic API ---
  window.sim = {
    w: W,
    h: H,
    balls: () => balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r })),
    addBall: (x, y, vx = 0, vy = 0, r) => { addBall(x, y, vx, vy, r); },
    clear: () => { balls.length = 0; draw(); },
    step,
  };

  // Seed one ball so the canvas isn't empty.
  addBall(W / 2, 60, 2.5, 0);
  loop();
})();
</script>
</body>
</html>
